import React from "react";
import { Routes, Route, Navigate, useLocation } from "react-router-dom";
import { AnimatePresence, motion } from "framer-motion";

import Navbar from "./components/Navbar";
import TopNav from "./components/TopNav";

import About from "./components/About";
import Resume from "./components/Resume";
import Projects from "./components/Projects";
import Skills from "./components/Skills";
import Contact from "./components/Contact";

// Subtle animated background component
const BackgroundElements = () => (
  <div className="fixed inset-0 z-[-1] overflow-hidden pointer-events-none">
    <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-accent-primary/10 blur-[120px] animate-blob"></div>
    <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-accent-secondary/10 blur-[120px] animate-blob animation-delay-2000"></div>
  </div>
);

function App() {
  const location = useLocation();

  return (
    <div className="min-h-screen bg-dark-bg text-gray-200 flex justify-center items-center p-4 md:p-10 relative">
      <BackgroundElements />

      <div className="max-w-7xl w-full grid grid-cols-1 lg:grid-cols-[300px_1fr] gap-6 lg:gap-10 relative z-10">

        {/* LEFT SIDEBAR */}
        <aside className="h-fit lg:sticky lg:top-10 z-20">
          <Navbar />
        </aside>

        {/* RIGHT CONTENT */}
        <main className="glass rounded-[2rem] p-6 sm:p-8 lg:p-10 relative min-h-[80vh] flex flex-col">
          <TopNav />

          {/* PAGE ANIMATION */}
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              transition={{ duration: 0.25, ease: "easeInOut" }}
            >
              <Routes location={location}>
                {/* Default */}
                <Route path="/" element={<Navigate to="/about" replace />} />

                {/* Pages */}
                <Route path="/about" element={<About />} />
                <Route path="/resume" element={<Resume />} />
                <Route path="/projects" element={<Projects />} />
                <Route path="/skills" element={<Skills />} />
                <Route path="/contact" element={<Contact />} />
              </Routes>
            </motion.div>
          </AnimatePresence>

          {/* Footer */}
          <footer className="mt-auto pt-10 text-center text-gray-500 text-sm border-t border-white/5">
            <p className="flex items-center justify-center gap-1">
              ┬⌐ 2026 Prabhat | Built with <span className="text-accent-primary">React</span> & <span className="text-accent-secondary">Tailwind</span>
            </p>
          </footer>
        </main>

      </div>
    </div>
  );
}

export default App;

import React from "react";
import { motion } from "framer-motion";

const About = () => {
  const techStack = [
    "Java",
    "Spring Boot",
    "REST APIs",
    "JWT",
    "SQL",
    "MySQL",
    "Git",
    "Maven",
  ];

  const quickStats = [
    { value: "4+", label: "Projects Built" },
    { value: "5+", label: "Certifications" },
    { value: "100%", label: "Dedication" },
  ];

  const featuredProjects = [
    {
      title: "Portfolio Website",
      img: "/src/assets/portfolio-preview.png",
      url: "prabhat.dev",
      description:
        "Personal portfolio showcasing experience, skills, and achievements.",
      tech: ["React", "Tailwind", "Framer Motion"]
    },
    {
      title: "Study Hub",
      img: "/src/assets/studyhub.png",
      url: "terminal.prabhat.dev",
      description:
        "A collaborative Study Hub platform designed for students to share, access, and organize study materials interactively.",
      tech: ["Java", "Spring Boot", "React", "MySQL"]
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.15, delayChildren: 0.2 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 24 } },
  };

  return (
    <motion.div
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      className="space-y-24"
    >
      {/* HERO / ABOUT SECTION */}
      <section id="about" className="scroll-mt-24 px-4 sm:px-6 md:px-8 mt-4">
        <motion.div variants={itemVariants} className="inline-block mb-4">
          <span className="bg-accent-primary/10 text-accent-primary border border-accent-primary/20 px-4 py-1.5 rounded-full text-sm font-mono shadow-[0_0_15px_rgba(59,130,246,0.2)]">
            Hello, World! ≡ƒæï
          </span>
        </motion.div>
        
        <motion.h2 variants={itemVariants} className="text-4xl sm:text-5xl md:text-6xl font-bold text-white mb-6 leading-tight tracking-tight">
          I'm <span className="text-gradient">Prabhat Kumar</span>,<br />
          Building Scalable Backends.
        </motion.h2>

        <motion.div variants={itemVariants} className="w-20 h-1.5 bg-gradient-to-r from-accent-primary to-accent-secondary rounded-full mb-8 shadow-[0_0_10px_rgba(139,92,246,0.5)]"></motion.div>

        <motion.div variants={itemVariants} className="text-gray-400 text-base sm:text-lg leading-relaxed space-y-6 max-w-3xl">
          <p>
            A passionate Java Backend Developer and B.Tech Computer Science student. I specialize in designing and building robust, high-performance APIs and scalable system architectures.
          </p>

          <p>
            My expertise lies in core backend technologies including{" "}
            <span className="text-gray-200 font-semibold border-b border-accent-secondary/50 pb-0.5">Java, Spring Boot, REST APIs, and SQL</span>, with a strong emphasis on clean code, secure authentication (JWT), and efficient database modeling.
          </p>
          
          <p>
            Driven by a constant desire to learn and solve complex engineering problems in collaborative, professional environments.
          </p>
        </motion.div>

        {/* TECH STACK CHIPS */}
        <motion.div variants={itemVariants} className="flex flex-wrap gap-3 mt-10">
          {techStack.map((tech, i) => (
            <motion.span
              key={tech}
              whileHover={{ scale: 1.05, y: -2 }}
              className="px-5 py-2 text-sm rounded-xl glass-card text-gray-200 font-medium cursor-pointer"
            >
              {tech}
            </motion.span>
          ))}
        </motion.div>

        {/* QUICK STATS */}
        <motion.div variants={itemVariants} className="grid grid-cols-1 sm:grid-cols-3 gap-6 mt-14">
          {quickStats.map((item, index) => (
            <motion.div
              key={item.label}
              whileHover={{ y: -5 }}
              className="glass p-6 rounded-2xl relative overflow-hidden group"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-accent-primary/5 to-accent-secondary/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
              <h4 className="text-4xl font-bold text-white mb-2 tracking-tight group-hover:text-accent-primary transition-colors">{item.value}</h4>
              <p className="text-xs text-gray-400 uppercase tracking-widest font-semibold">{item.label}</p>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* FEATURED PROJECTS PREVIEW */}
      <section
        id="featured-portfolios"
        className="px-4 sm:px-6 md:px-8 pb-10"
      >
        <motion.div variants={itemVariants} className="mb-10">
          <h2 className="text-3xl sm:text-4xl font-bold text-white mb-3 tracking-tight">
            Featured <span className="text-gradient">Work</span>
          </h2>
          <p className="text-gray-400 text-base max-w-2xl">
            A selection of my recent engineering projects.
          </p>
        </motion.div>

        <motion.div variants={itemVariants} className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {featuredProjects.map((project, index) => (
            <motion.div
              key={project.title}
              whileHover={{ y: -8 }}
              className="glass rounded-3xl overflow-hidden group border border-white/10 hover:border-accent-primary/30 transition-all duration-500"
            >
              <div className="w-full h-56 sm:h-64 bg-dark-bg overflow-hidden relative">
                <div className="absolute inset-0 bg-accent-primary/20 mix-blend-overlay opacity-0 group-hover:opacity-100 transition-opacity duration-500 z-10"></div>
                {/* Fallback pattern if image is missing */}
                <div className="absolute inset-0 opacity-20 bg-[radial-gradient(#3b82f6_1px,transparent_1px)] [background-size:20px_20px]"></div>
                <img
                  src={project.img}
                  alt={`${project.title} Interface`}
                  className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105 relative z-0"
                  style={{ objectPosition: "top" }}
                  onError={(e) => {
                    e.target.style.display = 'none'; // Hide broken images gracefully
                  }}
                />
              </div>
              <div className="p-8 relative">
                <div className="absolute top-0 right-8 -translate-y-1/2 bg-dark-surface border border-white/10 px-4 py-1.5 rounded-full text-xs font-mono text-gray-400 shadow-xl group-hover:border-accent-primary/30 transition-colors">
                  {project.url}
                </div>
                <h3 className="text-2xl font-bold text-white mb-3 group-hover:text-accent-primary transition-colors">{project.title}</h3>
                <p className="text-gray-400 text-sm leading-relaxed mb-6">
                  {project.description}
                </p>
                <div className="flex flex-wrap gap-2">
                  {project.tech.map(t => (
                    <span key={t} className="text-xs font-mono text-accent-secondary bg-accent-secondary/10 px-2 py-1 rounded-md">
                      {t}
                    </span>
                  ))}
                </div>
              </div>
            </motion.div>
          ))}
        </motion.div>
      </section>
    </motion.div>
  );
};

export default About;

import React, { useRef, useState } from 'react';
import emailjs from '@emailjs/browser';
import { motion } from 'framer-motion';
import { FaPaperPlane, FaUser, FaEnvelope, FaCommentAlt, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';
import { EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, EMAILJS_PUBLIC_KEY } from './emailjsConfig';

const Contact = () => {
  const formRef = useRef();
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const [error, setError] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSending(true);
    setError(null);
    setSent(false);
    try {
      await emailjs.sendForm(
        EMAILJS_SERVICE_ID,
        EMAILJS_TEMPLATE_ID,
        formRef.current,
        EMAILJS_PUBLIC_KEY
      );
      setSent(true);
      formRef.current.reset();
      setTimeout(() => setSent(false), 5000); // Clear success message after 5 seconds
    } catch (err) {
      setError('Failed to send message. Please try again.');
    } finally {
      setSending(false);
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { staggerChildren: 0.15, delayChildren: 0.1 } },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 24 } },
  };

  return (
    <motion.section 
      id="contact" 
      className="scroll-mt-24 px-4 sm:px-6 md:px-8 pb-16 mt-6 pt-10 border-t border-white/5"
      variants={containerVariants}
      initial="hidden"
      animate="visible"
    >
      <motion.div variants={itemVariants} className="mb-12 text-center md:text-left">
        <h2 className="text-3xl sm:text-4xl font-bold text-white mb-3 tracking-tight">
          Let's <span className="text-gradient">Connect</span>
        </h2>
        <p className="text-gray-400 text-base max-w-2xl mx-auto md:mx-0">
          Have a project in mind or just want to chat? Send me a message!
        </p>
      </motion.div>

      <div className="grid grid-cols-1 lg:grid-cols-[1fr_1.5fr] gap-8 items-center">
        
        {/* Left Info Card */}
        <motion.div variants={itemVariants} className="glass rounded-[2rem] p-8 sm:p-10 h-full flex flex-col justify-center relative overflow-hidden group border border-white/5 hover:border-accent-primary/20 transition-all duration-500">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-accent-primary to-accent-secondary transform origin-left scale-x-0 group-hover:scale-x-100 transition-transform duration-500"></div>
          
          <div className="p-4 bg-accent-primary/10 w-fit rounded-2xl text-accent-primary mb-6 group-hover:scale-110 transition-transform duration-300">
            <FaPaperPlane size={32} />
          </div>
          
          <h3 className="text-3xl font-bold text-white mb-6 leading-tight">Ready to build<br/>something <span className="text-accent-primary">great?</span></h3>
          
          <p className="text-gray-400 mb-10 leading-relaxed max-w-sm">
            I'm currently open to new backend development opportunities. Whether you have a question or just want to say hi, I'll try my best to get back to you!
          </p>
          
          <a
            href="mailto:prabhatmmg007@gmail.com"
            className="inline-flex items-center justify-center gap-3 px-8 py-4 bg-accent-primary text-white font-bold rounded-2xl hover:bg-blue-600 transition-all shadow-[0_0_20px_rgba(59,130,246,0.3)] hover:shadow-[0_0_30px_rgba(59,130,246,0.5)] active:scale-95 w-fit"
          >
            Say Hello ≡ƒæï
          </a>
        </motion.div>

        {/* Contact Form */}
        <motion.div variants={itemVariants} className="glass rounded-[2rem] p-6 sm:p-10 border border-white/5 relative">
          <form
            ref={formRef}
            onSubmit={handleSubmit}
            className="flex flex-col gap-6 relative z-10"
          >
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              {/* Name Input */}
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-500 group-focus-within:text-accent-primary transition-colors">
                  <FaUser />
                </div>
                <input
                  type="text"
                  name="name"
                  placeholder="Your Name"
                  className="w-full bg-dark-bg/50 text-white pl-11 pr-4 py-4 rounded-2xl border border-white/10 focus:border-accent-primary outline-none transition-all placeholder-gray-500 focus:bg-dark-surface hover:border-white/20"
                  required
                />
              </div>

              {/* Email Input */}
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-500 group-focus-within:text-accent-secondary transition-colors">
                  <FaEnvelope />
                </div>
                <input
                  type="email"
                  name="email"
                  placeholder="Your Email Address"
                  className="w-full bg-dark-bg/50 text-white pl-11 pr-4 py-4 rounded-2xl border border-white/10 focus:border-accent-secondary outline-none transition-all placeholder-gray-500 focus:bg-dark-surface hover:border-white/20"
                  required
                />
              </div>
            </div>

            {/* Message Input */}
            <div className="relative group">
              <div className="absolute top-5 left-0 pl-4 flex items-center pointer-events-none text-gray-500 group-focus-within:text-white transition-colors">
               <FaCommentAlt />
              </div>
              <textarea
                name="message"
                rows={5}
                placeholder="What's on your mind?"
                className="w-full bg-dark-bg/50 text-white pl-11 pr-4 py-4 rounded-2xl border border-white/10 focus:border-white/30 outline-none transition-all placeholder-gray-500 focus:bg-dark-surface hover:border-white/20 resize-none font-sans"
                required
              ></textarea>
            </div>

            {/* Submit Button & Status */}
            <div className="flex flex-col sm:flex-row items-center gap-4 mt-2">
              <button
                type="submit"
                className="w-full sm:w-auto px-10 py-4 bg-white text-dark-bg font-bold rounded-2xl hover:bg-gray-200 transition-all shadow-lg active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                disabled={sending}
              >
                {sending ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-dark-bg" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Sending...
                  </>
                ) : 'Send Message'}
              </button>

              {sent && (
                <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-2 text-green-400 font-medium px-4 py-2 bg-green-400/10 rounded-xl border border-green-400/20 w-full sm:w-auto justify-center">
                  <FaCheckCircle /> Message sent!
                </motion.div>
              )}
              {error && (
                <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-2 text-red-400 font-medium px-4 py-2 bg-red-400/10 rounded-xl border border-red-400/20 w-full sm:w-auto justify-center text-sm">
                  <FaExclamationCircle /> {error}
                </motion.div>
              )}
            </div>
          </form>
        </motion.div>

      </div>
    </motion.section>
  );
};

export default Contact;

import React, { useState } from "react";
import { 
  FaEnvelope, 
  FaMapMarkerAlt, 
